            # First remove all proper control characters like '\n',
            # '\r' or '\t'.
            s = "".join(c for c in s if ord(c) >= 32)
            # Then, if any '\' left (it might have started as '\\nn')
            # remove those too.
            while "\\" in s:
                s = s.replace("\\", "")
            return s
        return s

    args, kwargs = [clean_argument(x) for x in args], {x: clean_argument(y) for x, y in kwargs.items()}

    return reverse(viewname, args=args, kwargs=kwargs)

